color_decision.tailwind_theme_block:
/* paste into src/app/globals.css, AFTER @import 'tailwindcss'; — Tailwind 4 canonical syntax */
@import 'tailwindcss';

@theme {
  /* Colors — cold space */
  --color-bg: #080808;
  --color-bg-deep: #050508;
  --color-surface: #0F0B1A;
  --color-text: #EDEAF5;
  --color-text-muted: #8A82A8;
  --color-text-dim: #4A4560;
  --color-accent: #CEB7FF;
  --color-accent-bright: #E4D6FF;
  --color-accent-glow: rgba(179, 119, 255, 0.55);
  --color-accent-halo: rgba(206, 183, 255, 0.18);
  --color-border: #2A2240;
  --color-border-strong: #3B3158;

  /* Fonts — bound to next/font CSS variables */
  --font-display: var(--font-orbitron);
  --font-sans: var(--font-geist);
  --font-mono: var(--font-jetbrains-mono);
  --font-label: var(--font-bebas-neue);

  /* Type scale */
  --text-hero: clamp(2.5rem, 5.5vw + 1rem, 6rem);
  --text-name: clamp(2rem, 4vw + 0.5rem, 3.75rem);
  --text-message: clamp(0.875rem, 0.6vw + 0.6rem, 1.375rem);
  --text-corner: clamp(1.5rem, 2vw + 0.5rem, 2.5rem);
  --text-anchor: clamp(1.25rem, 1.5vw + 0.5rem, 2.25rem);
  --text-click: clamp(1.25rem, 1.8vw + 0.5rem, 2rem);

  /* Spacing container */
  --spacing-container: 1440px;

  /* Easing */
  --ease-out-expo: cubic-bezier(0.2, 0.8, 0.2, 1);
  --ease-float: cubic-bezier(0.45, 0, 0.55, 1);
}

@layer base {
  html { color-scheme: dark; scroll-behavior: smooth; }
  body {
    background: var(--color-bg);
    color: var(--color-text);
    font-family: var(--font-sans), ui-sans-serif, system-ui, sans-serif;
    -webkit-font-smoothing: antialiased;
    overflow-x: hidden;
  }
  ::selection { background: var(--color-accent-halo); color: var(--color-text); }
  :focus-visible { outline: 2px solid var(--color-accent); outline-offset: 3px; border-radius: 4px; }
  h1, h2 { font-family: var(--font-display), ui-sans-serif, system-ui, sans-serif; letter-spacing: 0.02em; }
  .label { font-family: var(--font-label), 'Bebas Neue', Impact, sans-serif; letter-spacing: 0.04em; text-transform: uppercase; }
  .mono { font-family: var(--font-mono), ui-monospace, monospace; }
}

/* Signature glow: only on I AM MATEUS and CLICK boxes */
.glow-stroke {
  -webkit-text-stroke: 2px var(--color-accent);
  color: transparent;
  text-shadow: 0 0 5px var(--color-accent-glow);
}

/* Starfield wrapper — canvas lives inside */
.starfield {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background: radial-gradient(ellipse 90% 60% at 50% 40%, #14102A 0%, #080808 70%);
}

/* Ground horizon glow — behind the globe */
.horizon-glow {
  position: absolute;
  inset: auto 0 -10% 0;
  height: 55%;
  background: radial-gradient(ellipse 80% 50% at 50% 100%, var(--color-accent-halo) 0%, transparent 65%);
  pointer-events: none;
  z-index: 1;
}

/* Motion — all transform/opacity only */
@keyframes float-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-6px); } }
@keyframes pulse-glow { 0%, 100% { text-shadow: 0 0 5px var(--color-accent-glow); } 50% { text-shadow: 0 0 12px var(--color-accent-glow), 0 0 24px var(--color-accent-halo); } }
@keyframes scroll-bounce { 0%, 100% { transform: translateY(0); opacity: 1; } 50% { transform: translateY(6px); opacity: 0.6; } }
@keyframes comet-streak { 0% { transform: translate(-20vw, -10vh) rotate(-20deg); opacity: 0; } 10% { opacity: 0.8; } 90% { opacity: 0.8; } 100% { transform: translate(120vw, 40vh) rotate(-20deg); opacity: 0; } }
@keyframes fade-up { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }

.reveal { animation: fade-up 600ms var(--ease-out-expo) both; animation-delay: calc(var(--reveal-i, 0) * 120ms); }
.float-slow { animation: float-slow 6s var(--ease-float) infinite; }
.pulse-glow { animation: pulse-glow 4s var(--ease-float) infinite; }
.scroll-bounce { animation: scroll-bounce 1.6s var(--ease-float) infinite; }

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
  .starfield canvas { display: none; }
  .starfield { background-image: radial-gradient(1px 1px at 20% 30%, #ffffff 50%, transparent 100%), radial-gradient(1px 1px at 70% 15%, #ceb7ff 50%, transparent 100%), radial-gradient(1.5px 1.5px at 45% 80%, #ffffff 50%, transparent 100%), radial-gradient(1px 1px at 85% 60%, #8a82a8 50%, transparent 100%), radial-gradient(ellipse 90% 60% at 50% 40%, #14102A 0%, #080808 70%); }
}

